INSERT INTO bible_verses (id, version_id, book_id, chapter_number, verse_number, verse_text) VALUES
('00000000-0000-0000-0002-000000000300', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000008', 1, 1, '当士师秉政的时候，国中遭遇饥荒。在犹大、伯利恒，有一个人带着妻子和两个儿子往摩押地去寄居。'),
('00000000-0000-0000-0002-000000000301', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000008', 1, 2, '这人名叫以利米勒，他的妻名叫拿俄米；他两个儿子，一个名叫玛伦，一个名叫基连，都是犹大伯利恒的以法他人。他们到了摩押地，就住在那里。'),
('00000000-0000-0000-0002-000000000302', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000008', 1, 3, '后来拿俄米的丈夫以利米勒死了，剩下妇人和她两个儿子。'),
('00000000-0000-0000-0002-000000000303', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000008', 1, 4, '这两个儿子娶了摩押女子为妻，一个名叫俄珥巴，一个名叫路得，在那里住了约有十年。'),
('00000000-0000-0000-0002-000000000304', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000008', 1, 5, '玛伦和基连二人也死了，剩下拿俄米，没有丈夫，也没有儿子。'),
('00000000-0000-0000-0002-000000000305', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000008', 1, 6, '她就与两个儿妇起身，要从摩押地归回；因为她在摩押地听见耶和华眷顾自己的百姓，赐粮食与他们。'),
('00000000-0000-0000-0002-000000000306', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000008', 1, 7, '于是她和两个儿妇起行离开所住的地方，要回犹大地去。'),
('00000000-0000-0000-0002-000000000307', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000008', 1, 8, '拿俄米对两个儿妇说：你们各人回娘家去吧。愿耶和华恩待你们，像你们恩待已死的人与我一样！'),
('00000000-0000-0000-0002-000000000308', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000008', 1, 9, '愿耶和华使你们各在新夫家中得平安！于是拿俄米与她们亲嘴；她们就放声而哭，'),
('00000000-0000-0000-0002-000000000309', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000008', 1, 10, '说：不然，我们必与你一同回你本国去。'),
('00000000-0000-0000-0002-000000000310', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000008', 1, 11, '拿俄米说：我女儿们哪，回去吧，为何要跟我去呢？我还能生子作你们的丈夫吗？'),
('00000000-0000-0000-0002-000000000311', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000008', 1, 12, '我女儿们哪，回去吧，我年纪老迈，不能再有丈夫；即或说，我还有指望，今夜有丈夫可以生子，'),
('00000000-0000-0000-0002-000000000312', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000008', 1, 13, '你们岂能等着他们长大呢？你们岂能等着他们不嫁别人呢？我女儿们哪，不要这样。我为你们的缘故甚是愁苦，因为耶和华的手攻击我。'),
('00000000-0000-0000-0002-000000000313', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000008', 1, 14, '两个儿妇又放声而哭，俄珥巴与婆婆亲嘴而别，只是路得舍不得拿俄米。'),
('00000000-0000-0000-0002-000000000314', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000008', 1, 15, '拿俄米说：看哪，你嫂子已经回她本国和她所拜的神那里去了，你也跟着你嫂子回去吧！'),
('00000000-0000-0000-0002-000000000315', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000008', 1, 16, '路得说：不要催我回去不跟随你。你往哪里去，我也往那里去；你在哪里住宿，我也在那里住宿；你的国就是我的国，你的神就是我的神。'),
('00000000-0000-0000-0002-000000000316', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000008', 1, 17, '你在哪里死，我也在那里死，也葬在那里。除非死能使你我相离！不然，愿耶和华重重地降罚与我。'),
('00000000-0000-0000-0002-000000000317', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000008', 1, 18, '拿俄米见路得定意要跟随自己去，就不再劝她了。'),
('00000000-0000-0000-0002-000000000318', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000008', 1, 19, '于是二人同行，来到伯利恒。她们到了伯利恒，合城的人就都惊讶。妇女们说：这是拿俄米吗？'),
('00000000-0000-0000-0002-000000000319', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000008', 1, 20, '拿俄米对她们说：不要叫我拿俄米，要叫我玛拉，因为全能者使我受了大苦。'),
('00000000-0000-0000-0002-000000000320', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000008', 1, 21, '我满满地出去，耶和华使我空空地回来。耶和华降祸与我，全能者使我受苦。既是这样，你们为何还叫我拿俄米呢？'),
('00000000-0000-0000-0002-000000000321', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000008', 1, 22, '拿俄米和她儿妇摩押女子路得，从摩押地回来到伯利恒，正是动手割大麦的时候。')
INSERT INTO bible_verses (id, version_id, book_id, chapter_number, verse_number, verse_text) VALUES
('00000000-0000-0000-0002-000000000330', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000065', 1, 1, '耶稣基督的仆人、雅各的弟兄犹大，写信给那被召、在父神里蒙爱、为耶稣基督保守的人。'),
('00000000-0000-0000-0002-000000000331', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000065', 1, 2, '愿怜恤、平安、慈爱多多地加给你们！'),
('00000000-0000-0000-0002-000000000332', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000065', 1, 3, '亲爱的弟兄啊，我想尽心写信给你们，论我们同得救恩的时候，就不得不写信劝你们，要为从前一次交付圣徒的真道竭力地争辩。'),
('00000000-0000-0000-0002-000000000333', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000065', 1, 4, '因为有些人偷着进来，就是自古被定受刑罚的，是不虔诚的，将我们神的恩变作放纵情欲的机会，并且不认独一的主宰我们主耶稣基督。'),
('00000000-0000-0000-0002-000000000334', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000065', 1, 5, '从前主救了他的百姓出埃及地，后来就把那些不信的灭绝了。这一切的事，你们虽然都知道，我却仍要提醒你们。'),
('00000000-0000-0000-0002-000000000335', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000065', 1, 6, '又有不守本位、离开自己住处的天使，主用锁链把他们永远拘留在黑暗里，等候大日的审判。'),
('00000000-0000-0000-0002-000000000336', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000065', 1, 7, '又如所多玛、蛾摩拉和周围城邑的人，也照他们一味地行淫，随从逆性的情欲，就受永火的刑罚，作为鉴戒。'),
('00000000-0000-0000-0002-000000000337', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000065', 1, 8, '这些做梦的人也像他们污秽身体，轻慢主治的，毁谤在尊位的。'),
('00000000-0000-0000-0002-000000000338', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000065', 1, 9, '天使长米迦勒为摩西的尸首与魔鬼争辩的时候，尚且不敢用毁谤的话罪责他，只说：主责备你吧！'),
('00000000-0000-0000-0002-000000000339', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000065', 1, 10, '但这些人毁谤他们所不知道的。他们本性所知道的事与那没有灵性的畜类一样，在这事上竟败坏了自己。'),
('00000000-0000-0000-0002-000000000340', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000065', 1, 11, '他们有祸了！因为走了该隐的道路，又为利往巴兰的错谬里直奔，并在可拉的背叛中灭亡了。'),
('00000000-0000-0000-0002-000000000341', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000065', 1, 12, '这样的人在你们的爱席上与你们同吃的时候，正是礁石。他们作牧人，只知喂养自己，无所惧怕；是没有雨的云彩，被风飘荡；是秋天没有果子的树，死而又死，连根被拔出来；'),
('00000000-0000-0000-0002-000000000342', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000065', 1, 13, '是海里的狂浪，涌出自己可耻的沫子来；是流荡的星，有墨黑的幽暗为他们永远存留。'),
('00000000-0000-0000-0002-000000000343', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000065', 1, 14, '亚当的七世孙以诺曾预言这些人说：看哪，主带着他的千万圣者降临，'),
('00000000-0000-0000-0002-000000000344', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000065', 1, 15, '要在众人身上行审判，证实那一切不敬虔的人所妄行一切不敬虔的事，又证实不敬虔之罪人所说顶撞他的刚愎话。'),
('00000000-0000-0000-0002-000000000345', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000065', 1, 16, '这些人是私下议论，常发怨言的，随从自己的情欲而行，口中说夸大的话，为得便宜谄媚人。'),
('00000000-0000-0000-0002-000000000346', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000065', 1, 17, '亲爱的弟兄啊，你们要记念我们主耶稣基督之使徒从前所说的话。'),
('00000000-0000-0000-0002-000000000347', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000065', 1, 18, '他们曾对你们说过，末世必有好讥诮的人随从自己不敬虔的私欲而行。'),
('00000000-0000-0000-0002-000000000348', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000065', 1, 19, '这就是那些引人结党、属乎血气、没有圣灵的人。'),
('00000000-0000-0000-0002-000000000349', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000065', 1, 20, '亲爱的弟兄啊，你们却要在至圣的真道上造就自己，在圣灵里祷告，'),
('00000000-0000-0000-0002-000000000350', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000065', 1, 21, '保守自己常在神的爱中，仰望我们主耶稣基督的怜悯，直到永生。'),
('00000000-0000-0000-0002-000000000351', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000065', 1, 22, '有些人存疑心，你们要怜悯他们；'),
('00000000-0000-0000-0002-000000000352', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000065', 1, 23, '有些人你们要从火中抢出来，搭救他们；有些人你们要存惧怕的心怜悯他们，连那被情欲沾染的衣服也当厌恶。'),
('00000000-0000-0000-0002-000000000353', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000065', 1, 24, '那能保守你们不失脚、叫你们无瑕无疵、欢欢喜喜站在他荣耀之前的我们的救主独一的神，'),
('00000000-0000-0000-0002-000000000354', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000065', 1, 25, '愿荣耀、威严、能力、权柄，因我们的主耶稣基督归与他，从万古以前并现今，直到永永远远。阿们！')
INSERT INTO bible_verses (id, version_id, book_id, chapter_number, verse_number, verse_text) VALUES
('00000000-0000-0000-0002-000000000360', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000057', 1, 1, '为基督耶稣被囚的保罗，同兄弟提摩太，写信给我们所亲爱的同工腓利门，'),
('00000000-0000-0000-0002-000000000361', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000057', 1, 2, '和妹子亚腓亚，并与我们同当兵的亚基布，以及在你家的教会。'),
('00000000-0000-0000-0002-000000000362', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000057', 1, 3, '愿恩惠、平安从神我们的父和主耶稣基督归与你们！'),
('00000000-0000-0000-0002-000000000363', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000057', 1, 4, '我祷告的时候提到你，常为我的神感谢你；'),
('00000000-0000-0000-0002-000000000364', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000057', 1, 5, '因听说你的爱心并你向主耶稣和众圣徒的信心'),
('00000000-0000-0000-0002-000000000365', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000057', 1, 6, '（我祷告的时候提到你，常为我的神感谢你；）'),
('00000000-0000-0000-0002-000000000366', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000057', 1, 7, '愿你与人所同有的信心显出功效，使人知道你们各样善事都是为基督作的。'),
('00000000-0000-0000-0002-000000000367', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000057', 1, 8, '兄弟啊，我为你的爱心大有快乐，大得安慰，因众圣徒的心从你得了畅快。'),
('00000000-0000-0000-0002-000000000368', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000057', 1, 9, '我虽然靠着基督能放胆吩咐你合宜的事，'),
('00000000-0000-0000-0002-000000000369', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000057', 1, 10, '然而像我这有年纪的保罗，现在又是为基督耶稣被囚的，'),
('00000000-0000-0000-0002-000000000370', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000057', 1, 11, '就是凭着爱心求你。有我在捆锁中所生的儿子阿尼西母求你。'),
('00000000-0000-0000-0002-000000000371', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000057', 1, 12, '他从前与你没有益处，但如今与你我都有益处。'),
('00000000-0000-0000-0002-000000000372', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000057', 1, 13, '我现在打发他亲自回你那里去；他是我心上的人。'),
('00000000-0000-0000-0002-000000000373', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000057', 1, 14, '我本来有意将他留下，在我为福音所受的捆锁中替你伺候我。'),
('00000000-0000-0000-0002-000000000374', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000057', 1, 15, '但不知道你的意思，我就不敢这样行；使你的善行不是出于勉强，乃是出于甘心。'),
('00000000-0000-0000-0002-000000000375', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000057', 1, 16, '他暂时离开你，或者是叫你永远得着他，'),
('00000000-0000-0000-0002-000000000376', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000057', 1, 17, '不再是奴仆，乃是高过奴仆，是亲爱的兄弟。在我实在是如此，何况在你呢！这也不拘是按肉体说，是按主说。'),
('00000000-0000-0000-0002-000000000377', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000057', 1, 18, '你若以我为同伴，就收纳他，如同收纳我一样。'),
('00000000-0000-0000-0002-000000000378', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000057', 1, 19, '他若亏负你，或欠你什么，都归在我的账上，'),
('00000000-0000-0000-0002-000000000379', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000057', 1, 20, '我必偿还。这是我保罗亲笔写的。我并不用对你说，连你自己也是亏欠于我。'),
('00000000-0000-0000-0002-000000000380', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000057', 1, 21, '兄弟啊，望你使我在主里因你得快乐，并望你使我的心在基督里得畅快。'),
('00000000-0000-0000-0002-000000000381', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000057', 1, 22, '我写信给你，深信你必顺服，知道你所行的必过于我所说的。'),
('00000000-0000-0000-0002-000000000382', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000057', 1, 23, '你还要给我预备住处，因为我盼望借着你们的祷告，必蒙恩到你们那里去。'),
('00000000-0000-0000-0002-000000000383', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000057', 1, 24, '与我同坐监的亚里达古问你安。'),
('00000000-0000-0000-0002-000000000384', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000057', 1, 25, '愿我们主耶稣基督的恩常在你的心里。阿们！')
